/**
 * Aggregation service — analytics and reporting over order data.
 *
 * Depends on:
 * - OrderRepository (data layer) for reading order data
 *
 * Provides summary statistics, breakdowns by status and user,
 * and time-based aggregations for dashboards and reporting.
 */

import type { Order, OrderStatus } from '../models/order.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import { Logger } from '../utils/logger.js';

/**
 * Summary statistics for a set of orders.
 */
export interface OrderSummary {
  totalOrders: number;
  totalRevenue: number;
  averageOrderValue: number;
  minOrderValue: number;
  maxOrderValue: number;
}

/**
 * Breakdown of orders by status.
 */
export interface StatusBreakdown {
  status: OrderStatus;
  count: number;
  revenue: number;
}

/**
 * Per-user order statistics.
 */
export interface UserOrderStats {
  userId: string;
  orderCount: number;
  totalSpent: number;
  averageOrderValue: number;
}

/**
 * Time-bucketed aggregation result.
 */
export interface TimeBucket {
  period: string;
  orderCount: number;
  revenue: number;
}

export class AggregationService {
  private logger = new Logger('AggregationService');

  constructor(private orderRepository: OrderRepository) {}

  /**
   * Get summary statistics for all orders.
   */
  getOrderSummary(): OrderSummary {
    this.logger.info('Generating order summary');
    const orders = this.orderRepository.findAll();

    if (orders.length === 0) {
      return {
        totalOrders: 0,
        totalRevenue: 0,
        averageOrderValue: 0,
        minOrderValue: 0,
        maxOrderValue: 0,
      };
    }

    const totals = orders.map((o) => o.total);
    const totalRevenue = totals.reduce((sum, t) => sum + t, 0);

    return {
      totalOrders: orders.length,
      totalRevenue,
      averageOrderValue: totalRevenue / orders.length,
      minOrderValue: Math.min(...totals),
      maxOrderValue: Math.max(...totals),
    };
  }

  /**
   * Get order counts and revenue broken down by status.
   */
  getStatusBreakdown(): StatusBreakdown[] {
    this.logger.info('Generating status breakdown');
    const orders = this.orderRepository.findAll();

    const statusMap = new Map<OrderStatus, { count: number; revenue: number }>();

    for (const order of orders) {
      const existing = statusMap.get(order.status) || { count: 0, revenue: 0 };
      existing.count += 1;
      existing.revenue += order.total;
      statusMap.set(order.status, existing);
    }

    return Array.from(statusMap.entries()).map(([status, data]) => ({
      status,
      count: data.count,
      revenue: data.revenue,
    }));
  }

  /**
   * Get order statistics per user.
   */
  getUserOrderStats(userId?: string): UserOrderStats[] {
    this.logger.info('Generating user order stats');
    let orders: Order[];

    if (userId) {
      orders = this.orderRepository.findByUserId(userId);
    } else {
      orders = this.orderRepository.findAll();
    }

    const userMap = new Map<string, { count: number; total: number }>();

    for (const order of orders) {
      const existing = userMap.get(order.userId) || { count: 0, total: 0 };
      existing.count += 1;
      existing.total += order.total;
      userMap.set(order.userId, existing);
    }

    return Array.from(userMap.entries()).map(([uid, data]) => ({
      userId: uid,
      orderCount: data.count,
      totalSpent: data.total,
      averageOrderValue: data.count > 0 ? data.total / data.count : 0,
    }));
  }

  /**
   * Get revenue for a specific status.
   */
  getRevenueByStatus(status: OrderStatus): number {
    const orders = this.orderRepository.findByStatus(status);
    return orders.reduce((sum, o) => sum + o.total, 0);
  }

  /**
   * Aggregate orders into daily time buckets.
   */
  getDailyAggregation(startDate: Date, endDate: Date): TimeBucket[] {
    this.logger.info('Generating daily aggregation');

    if (startDate > endDate) {
      throw new Error('startDate must be before or equal to endDate');
    }

    const orders = this.orderRepository.findAll();
    const bucketMap = new Map<string, { count: number; revenue: number }>();

    // Initialize all days in the range
    const current = new Date(startDate);
    current.setHours(0, 0, 0, 0);
    const end = new Date(endDate);
    end.setHours(0, 0, 0, 0);

    while (current <= end) {
      const key = current.toISOString().split('T')[0]!;
      bucketMap.set(key, { count: 0, revenue: 0 });
      current.setDate(current.getDate() + 1);
    }

    // Fill in order data
    for (const order of orders) {
      const dayKey = order.createdAt.toISOString().split('T')[0]!;
      const bucket = bucketMap.get(dayKey);
      if (bucket) {
        bucket.count += 1;
        bucket.revenue += order.total;
      }
    }

    return Array.from(bucketMap.entries())
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([period, data]) => ({
        period,
        orderCount: data.count,
        revenue: data.revenue,
      }));
  }

  /**
   * Get the top N users by total spending.
   */
  getTopUsers(limit: number): UserOrderStats[] {
    if (limit < 1) {
      throw new Error('Limit must be at least 1');
    }

    const stats = this.getUserOrderStats();
    return stats
      .sort((a, b) => b.totalSpent - a.totalSpent)
      .slice(0, limit);
  }
}

